const cloud = require("wx-server-sdk");
cloud.init({ env: cloud.DYNAMIC_CURRENT_ENV });
const db = cloud.database();
const _ = db.command;

function nowMs() {
  return Date.now();
}

function genTraceId() {
  const rand = Math.floor(1000 + Math.random() * 9000);
  return `timerCancelOrder_${nowMs()}_${rand}`;
}

exports.main = async (event, context) => {
  const traceId = genTraceId();
  const now = nowMs();

  console.log('[timerCancelOrder] start', new Date().toISOString(), traceId);

  try {
    const res = await db
      .collection("orders")
      .where({ status: "PENDING", expire_at: _.lte(now), modified: 1 })
      .limit(100)
      .get();

    for (const order of res.data) {
      await db.runTransaction(async (tx) => {
        const upd = await tx
          .collection("orders")
          .where({ order_no: order.order_no, status: "PENDING", modified: 1 })
          .update({
            data: {
              status: "CANCELLED",
              cancelled_at: nowMs(),
              status_history: _.push({
                each: [{ status: "CANCELLED", at: nowMs(), trace_id: traceId }]
              })
            }
          });

        if (upd.stats.updated !== 1) {
          return;
        }

        if (Array.isArray(order.items)) {
          for (const it of order.items) {
            await tx
              .collection("skus")
              .where({ _id: it.sku_id })
              .update({ data: { stock: _.inc(it.qty) } });
          }
        }
      });
    }

    console.log('[timerCancelOrder] done', res.data.length, 'orders processed');
    return { code: 0, msg: "ok", trace_id: traceId, processed: res.data.length };
  } catch (err) {
    return { code: 1, msg: err.message || "ERR_TIMER_CANCEL", trace_id: traceId };
  }
};
